from source import longest_common_subsequence


def is_subsequence(s, t):
    it = iter(t)
    return all(c in it for c in s)


def test_match_advances_both_strings():
    result = longest_common_subsequence('AGCAT', 'GAC')
    assert is_subsequence(result, 'AGCAT'), (
        f"result {result!r} is not a subsequence of 'AGCAT'"
    )
    assert is_subsequence(result, 'GAC'), (
        f"result {result!r} is not a subsequence of 'GAC'; "
        f"bug causes the same b-character to be re-matched"
    )
    assert len(result) == 2, (
        f"expected LCS length 2 ('AC' or 'GC'), got {len(result)} ({result!r}); "
        f"bug inflates length by never advancing b past a matched character"
    )
